268	export async function driveRunToWin(
269	  page: Page,
270	  options: BotOptions = {}
271	): Promise<void> {
272	  ensurePageDiagnostics(page);
273	  const state = page.getByTestId("game-state");
274	  const policyState: BotPolicyState = {
275	    visitedByDepth: new Map<number, Set<string>>(),
276	    rng: seededRandom(options.seed ?? resolveCampaignSeed()),
277	    log: options.log ?? console.log,
278	    lastActions: [],
279	    loopBreaker: emptyLoopBreakerState(),
280	    descendIntent: null,
281	    lastAction: null
282	  };
283	  let turns = 0;
284	  let lastSignature = "";
285	  let stuckRepeats = 0;
286	  let lastProgressDepth = 0;
287	  let lastProgressVisitedCount = 0;
288	  let noProgressTurns = 0;
289	  let diagnosticsWritten = false;
290	
291	  try {
292	    while (turns < MAX_TURN_CAP) {
293	      await settleUi(page);
294	
295	      const shell = await readShellSnapshot(state);
296	      updateBotDiagnostics(page, shell, policyState, noProgressTurns);
297	      if (isTransitionActive(shell)) {
298	        const transition = await pollFloorTransition(page, state, shell);
299	        updateBotDiagnostics(page, transition.shell, policyState, noProgressTurns);
300	        if (transition.timedOut) {
301	          await dumpStuckState(page, "floor transition wedged");
302	          diagnosticsWritten = true;
303	          throw new Error("floor transition wedged");
304	        }
305	
306	        stuckRepeats = 0;
307	        lastSignature = "";
308	        noProgressTurns = 0;
309	        clearDescendIntent(policyState);
310	        updateBotDiagnostics(page, transition.shell, policyState, noProgressTurns);
311	        continue;
312	      }
313	
314	      if (shell.screen !== "playing") {
315	        if (shell.terminalStatus === "WIN") {
316	          return;
317	        }
318	        await dumpStuckState(page, "left playing screen before WIN");
319	        diagnosticsWritten = true;
320	        throw new BotFailure("left playing screen before WIN", {
321	          shell,
322	          hud: await readHudSnapshot(page),
323	          player: null,
324	          gameStateAttributes: await readGameStateAttributes(page),
325	          recentLogLines: await readRecentLogLines(page),
326	          botState: ensurePageDiagnostics(page).botState,
327	          consoleMessages: ensurePageDiagnostics(page).consoleMessages,
328	          reason: `screen=${shell.screen} terminal=${shell.terminalStatus}`
329	        });
330	      }
331	
332	      if (shell.terminalStatus === "WIN") {
333	        return;
334	      }
335	
336	      const beforeTurn = shell.turn;
337	      const decision = await choosePolicyKey(page, shell, policyState);
338	      recordAction(policyState, shell, decision);
339	      updateBotDiagnostics(page, shell, policyState, noProgressTurns);
340	      if (decision.key === null) {
341	        await waitForUiFrame(page);
342	      } else {
343	        await pressGameplayKey(page, decision.key);
344	      }
345	
346	      let after = await readShellSnapshot(state);
347	      let waitedForTransition = false;
348	      if (isTransitionActive(after)) {
349	        const transition = await pollFloorTransition(page, state, after);
350	        updateBotDiagnostics(page, transition.shell, policyState, noProgressTurns);
351	        if (transition.timedOut) {
352	          await dumpStuckState(page, "floor transition wedged");
353	          diagnosticsWritten = true;
354	          throw new Error("floor transition wedged");
355	        }
356	
357	        waitedForTransition = true;
358	        stuckRepeats = 0;
359	        lastSignature = "";
360	        noProgressTurns = 0;
361	        clearDescendIntent(policyState);
362	        after = transition.shell;
363	      }
364	
365	      if (after.terminalStatus === "WIN") {
366	        updateBotDiagnostics(page, after, policyState, noProgressTurns);
367	        return;
368	      }
369	
370	      if (after.screen !== "playing") {
371	        updateBotDiagnostics(page, after, policyState, noProgressTurns);
372	        await dumpStuckState(page, "left playing screen after action before WIN");
373	        diagnosticsWritten = true;
374	        throw new BotFailure("left playing screen after action before WIN", {
375	          shell: after,
376	          hud: await readHudSnapshot(page),
377	          player: null,
378	          gameStateAttributes: await readGameStateAttributes(page),
379	          recentLogLines: await readRecentLogLines(page),
380	          botState: ensurePageDiagnostics(page).botState,
381	          consoleMessages: ensurePageDiagnostics(page).consoleMessages,
382	          reason: `screen=${after.screen} terminal=${after.terminalStatus}`
383	        });
384	      }
385	
386	      if (after.turn === beforeTurn && after.screen === "playing") {
387	        if (waitedForTransition) {
388	          updateBotDiagnostics(page, after, policyState, noProgressTurns);
389	          continue;
390	        }
391	
392	        const signature = await progressSignature(page, after);
393	        stuckRepeats = signature === lastSignature ? stuckRepeats + 1 : 0;
394	        lastSignature = signature;
395	        updateBotDiagnostics(page, after, policyState, noProgressTurns);
396	        if (stuckRepeats >= NO_PROGRESS_REPEAT_CAP) {
397	          await dumpStuckState(
398	            page,
399	            `no turn progress for ${NO_PROGRESS_REPEAT_CAP} identical states`
400	          );
401	          diagnosticsWritten = true;
402	          throw new Error("bot stuck: no turn progress");
403	        }
404	        continue;
405	      }
406	
407	      stuckRepeats = 0;
408	      lastSignature = "";
409	      turns += 1;
410	      await markPlayerVisitedFromPage(page, after.depth, policyState);
411	
412	      const visitedCount = visitedCountForDepth(policyState, after.depth);
413	      const depthChanged = after.depth !== shell.depth;
414	      if (depthChanged) {
415	        clearDescendIntent(policyState);
416	      }
417	
418	      const madeProgress =
419	        depthChanged ||
420	        after.depth !== lastProgressDepth ||
421	        visitedCount > lastProgressVisitedCount;
422	      if (madeProgress) {
423	        lastProgressDepth = after.depth;
424	        lastProgressVisitedCount = visitedCount;
425	        noProgressTurns = 0;
426	      } else {
427	        noProgressTurns += Math.max(1, after.turn - beforeTurn);
428	      }
429	
430	      updateBotDiagnostics(page, after, policyState, noProgressTurns);
431	
432	      if (noProgressTurns >= NO_VISITED_PROGRESS_TURNS) {
433	        await dumpStuckState(
434	          page,
435	          `no exploration progress for ${noProgressTurns} game turns at depth ${after.depth}`
436	        );
437	        diagnosticsWritten = true;
438	        throw new Error(
439	          `bot stuck: no new visited cells for ${noProgressTurns} game turns at depth ${after.depth}`
440	        );
441	      }
442	
443	      if (turns % TELEMETRY_INTERVAL_TURNS === 0) {
444	        await logTelemetry(page, after, policyState);
445	      }
446	    }
447	
448	    const shell = await readShellSnapshot(state);
449	    updateBotDiagnostics(page, shell, policyState, noProgressTurns);
450	    await dumpStuckState(
451	      page,
452	      `turn cap ${MAX_TURN_CAP} exceeded at depth ${shell.depth}`
453	    );
454	    diagnosticsWritten = true;
455	    throw new Error(
456	      `bot exceeded turn cap (${MAX_TURN_CAP}) at depth ${shell.depth}`
457	    );
458	  } catch (error) {
459	    if (!diagnosticsWritten) {
460	      await dumpStuckState(
461	        page,
462	        `driveRunToWin error: ${
463	          error instanceof Error ? error.message : String(error)
464	        }`
465	      );
466	    }
467	    throw error;
468	  }
469	}
