545	async function settleUi(page: Page): Promise<void> {
546	  const state = page.getByTestId("game-state");
547	  const shell = await readShellSnapshot(state);
548	
549	  if (shell.screen !== "playing") {
550	    return;
551	  }
552	
553	  if (isTransitionActive(shell)) {
554	    return;
555	  }
556	
557	  const transition = page.getByTestId("transition-overlay");
558	  if (await transition.isVisible().catch(() => false)) {
559	    return;
560	  }
561	
562	  if (shell.panelMode === "dialogue") {
563	    await page.keyboard.press("Escape");
564	    await expect(state).toHaveAttribute("data-panel-mode", "inspect");
565	    return;
566	  }
567	
568	  if (shell.panelMode !== "inspect") {
569	    await page.keyboard.press("Escape");
570	    await expect(state).toHaveAttribute("data-panel-mode", "inspect");
571	    return;
572	  }
573	
574	  if (shell.diaryOpen) {
575	    await page.keyboard.press("Tab");
576	    await expect(state).toHaveAttribute("data-diary-open", "false");
577	  }
578	
579	  const confirm = page.locator('[data-confirm-prompt="true"]');
580	  if (await confirm.isVisible().catch(() => false)) {
581	    const text = (await confirm.textContent()) ?? "";
582	    if (text.toLowerCase().includes("descend")) {
583	      await page.keyboard.press("y");
584	    } else {
585	      await page.keyboard.press("n");
586	    }
587	  }
588	
589	  await expect(state).toHaveAttribute("data-input-locked", "false", {
590	    timeout: 30_000
591	  });
592	}
