594	async function choosePolicyKey(
595	  page: Page,
596	  shell: ShellSnapshot,
597	  policyState: BotPolicyState
598	): Promise<BotDecision> {
599	  const cells = await readGridCells(page);
600	  const player = findPlayer(cells);
601	  const hud = await readHudSnapshot(page);
602	
603	  if (player === null) {
604	    return botDecision(".", "wait:player-not-found");
605	  }
606	
607	  resetDescendIntentIfStairsVisitChanged(policyState, shell, cells, player);
608	  markVisited(policyState.visitedByDepth, shell.depth, player);
609	  await updateLoopBreaker(page, shell, policyState, cells, player, hud);
610	  const visited = policyState.visitedByDepth.get(shell.depth) ?? new Set();
611	  const blockedCells = blockedCellsForLoopBreak(policyState, shell, cells);
612	
613	  const adjacentEnemy = findAdjacentEnemy(cells, player);
614	  if (
615	    adjacentEnemy !== null &&
616	    !blockedCells.has(posKey(adjacentEnemy.x, adjacentEnemy.y))
617	  ) {
618	    return botDecision(
619	      directionKeyToward(player, adjacentEnemy),
620	      `attack-adjacent-enemy:${posKey(adjacentEnemy.x, adjacentEnemy.y)}`

 620	      `attack-adjacent-enemy:${posKey(adjacentEnemy.x, adjacentEnemy.y)}`
 621	    );
 622	  }
 623	
 624	  if (hasItemUnderfoot(cells, player)) {
 625	    return botDecision("g", "pickup-underfoot");
 626	  }
 627	
 628	  if (hud !== null && hud.hpRatio <= 0.45) {
 629	    const healed = await tryHeal(page);
 630	    if (healed) {
 631	      return botDecision(null, "use-healing-item");
 632	    }
 633	  }
 634	
 635	  if (shell.depth >= FINAL_DEPTH) {
 636	    if (isOnHoard(cells, player)) {
 637	      return botDecision("T", "take-hoard");
 638	    }
 639	
 640	    const hoard = findTargetCells(
 641	      cells,
 642	      (cell) => cell.featureKind === "hoard"
 643	    );
 644	    const hoardRoute = routeStep(player, hoard, cells, blockedCells);
 645	    if (hoardRoute !== null) {
 646	      return botDecision(hoardRoute, "route-to-hoard");
 647	    }
 648	  }
 649	
 650	  if (shell.depth < FINAL_DEPTH && isOnStairs(cells, player)) {
 651	    const stairsKey = posKey(player.x, player.y);
 652	    if (hasPendingDescendIntent(policyState, shell.depth, stairsKey)) {
 653	      return botDecision(null, "wait:descend-pending");
 654	    }
 655	
 656	    policyState.descendIntent = { depth: shell.depth, stairsKey };
 657	    return botDecision(">", "descend-on-stairs");
 658	  }
 659	
 660	  if (shell.depth < FINAL_DEPTH) {
 661	    const stairs = findTargetCells(
 662	      cells,
 663	      (cell) => cell.glyph === ">" || cell.terrain === "stairs_down"
 664	    );
 665	    const stairsRoute = routeStep(player, stairs, cells, blockedCells);
 666	    if (stairsRoute !== null) {
 667	      return botDecision(stairsRoute, "route-to-stairs");
 668	    }
 669	  }
 670	
 671	  const exploreStep = frontierStep(player, cells, visited, blockedCells);
 672	  if (exploreStep !== null) {
 673	    return botDecision(exploreStep, "explore-frontier");
 674	  }
 675	
 676	  return botDecision(
 677	    boxedBreakKey(player, cells, policyState.rng, blockedCells),
 678	    "boxed-break"
 679	  );
 680	}
