 682	async function logTelemetry(
 683	  page: Page,
 684	  shell: ShellSnapshot,
 685	  policyState: BotPolicyState
 686	): Promise<void> {
 687	  const cells = await readGridCells(page);
 688	  const player = findPlayer(cells);
 689	  if (player !== null) {
 690	    markVisited(policyState.visitedByDepth, shell.depth, player);
 691	  }
 692	
 693	  const walkable = knownWalkableKeys(cells);
 694	  const visited = policyState.visitedByDepth.get(shell.depth) ?? new Set();
 695	  const visitedKnownCount = [...visited].filter((key) =>
 696	    walkable.has(key)
 697	  ).length;
 698	  const visitedPercent =
 699	    walkable.size === 0
 700	      ? 0
 701	      : Math.min(100, (visitedKnownCount / walkable.size) * 100);
 702	  const hud = await readHudSnapshot(page);
 703	  const hp = hud === null ? "unknown" : `${hud.hpCurrent}/${hud.hpMax}`;
 704	  const lastAction = policyState.lastAction ?? "none";
 705	
 706	  policyState.log(
 707	    `[full-clear bot] depth=${shell.depth} turn=${shell.turn} visited=${visitedPercent.toFixed(
 708	      1
 709	    )}% hp=${hp} lastAction=${lastAction}`
 710	  );
 711	}
