 762	async function updateLoopBreaker(
 763	  page: Page,
 764	  shell: ShellSnapshot,
 765	  policyState: BotPolicyState,
 766	  cells: readonly GridCell[],
 767	  player: GridPosition,
 768	  hud: HudSnapshot | null
 769	): Promise<void> {
 770	  const signature = JSON.stringify({
 771	    depth: shell.depth,
 772	    player,
 773	    hp: hud === null ? null : `${hud.hpCurrent}/${hud.hpMax}`,
 774	    enemies: visibleEnemyKeys(cells),
 775	    logTail: (await readRecentLogLines(page)).slice(-4)
 776	  });
 777	  const previous = policyState.loopBreaker;
 778	  const action = policyState.lastAction;
 779	  const repeated =
 780	    action !== null &&
 781	    action === previous.previousAction &&
 782	    signature === previous.previousSignature;
 783	  const repeatCount = repeated ? previous.repeatCount + 1 : 0;
 784	  const activeAvoid =
 785	    previous.avoidEnemyKey !== null &&
 786	    shell.turn <= previous.avoidUntilTurn &&
 787	    enemyStillVisible(cells, previous.avoidEnemyKey)
 788	      ? {
 789	          avoidEnemyKey: previous.avoidEnemyKey,
 790	          avoidUntilTurn: previous.avoidUntilTurn
 791	        }
 792	      : {
 793	          avoidEnemyKey: null,
 794	          avoidUntilTurn: 0
 795	        };
 796	  const attackTarget = action === null ? null : attackTargetKey(action);
 797	
 798	  if (
 799	    repeatCount >= NO_OBSERVABLE_CHANGE_ACTION_CAP &&
 800	    attackTarget !== null &&
 801	    enemyStillVisible(cells, attackTarget)
 802	  ) {
 803	    policyState.log(
 804	      `[full-clear bot] loop-breaker avoiding enemy ${attackTarget} after ${repeatCount} unchanged ${action} actions`
 805	    );
 806	    policyState.loopBreaker = {
 807	      previousAction: action,
 808	      previousSignature: signature,
 809	      repeatCount: 0,
 810	      avoidEnemyKey: attackTarget,
 811	      avoidUntilTurn: shell.turn + LOOP_BREAK_AVOID_TURNS
 812	    };
 813	    return;
 814	  }
 815	
 816	  policyState.loopBreaker = {
 817	    previousAction: action,
 818	    previousSignature: signature,
 819	    repeatCount,
 820	    ...activeAvoid
 821	  };
 822	}
 823	
 824	function blockedCellsForLoopBreak(
 825	  policyState: BotPolicyState,
 826	  shell: ShellSnapshot,
 827	  cells: readonly GridCell[]
 828	): ReadonlySet<string> {
 829	  const avoidKey = policyState.loopBreaker.avoidEnemyKey;
 830	  if (
 831	    avoidKey === null ||
 832	    shell.turn > policyState.loopBreaker.avoidUntilTurn ||
 833	    !enemyStillVisible(cells, avoidKey)
 834	  ) {
 835	    return new Set();
 836	  }
 837	
 838	  return new Set([avoidKey]);
 839	}
 840	
 841	function attackTargetKey(action: string): string | null {
 842	  const prefix = "attack-adjacent-enemy:";
 843	  if (!action.startsWith(prefix)) {
 844	    return null;
 845	  }
 846	
 847	  return action.slice(prefix.length);
 848	}
