 850	function visibleEnemyKeys(cells: readonly GridCell[]): readonly string[] {
 851	  return cells
 852	    .filter((cell) => cell.layer === "enemy" && cell.fog === "visible")
 853	    .map((cell) => posKey(cell.x, cell.y))
 854	    .sort();
 855	}
 856	
 857	function enemyStillVisible(cells: readonly GridCell[], key: string): boolean {
 858	  return visibleEnemyKeys(cells).includes(key);
 859	}
