 984	    if (Date.now() - startedAtMs >= FLOOR_TRANSITION_TIMEOUT_MS) {
 985	      return {
 986	        timedOut: true,
 987	        shell
 988	      };
 989	    }
 990	
 991	    await page.waitForTimeout(FLOOR_TRANSITION_POLL_MS);
 992	    shell = await readShellSnapshot(state);
 993	  }
