115	export const checkActionLegality = (
116	  state: GameState,
117	  action: PlayerAction,
118	): ActionLegality => {
119	  if (state.run.terminalStatus !== "ACTIVE") {
120	    return illegal(`run is terminal (${state.run.terminalStatus})`);
121	  }
122	
123	  switch (action.kind) {
124	    case "move":
