126	    case "attack":
127	      return checkAttackAction(state, action);
128	    case "use_item":
129	      return checkUseItemAction(state, action);
130	    case "pickup":
131	      return checkPickupAction(state);
132	    case "talk":
133	      return checkTalkAction(state, action);
134	    case "wait":
135	      return LEGAL_ACTION;
136	    case "descend":
137	      return checkDescendAction(state);
138	    case "inspect":
139	      return checkInspectAction(state, action);
140	    case "abort":
141	      return LEGAL_ACTION;
142	  }
