145	export const getAvailableActions = (state: GameState): readonly PlayerAction[] => {
146	  if (state.run.terminalStatus !== "ACTIVE") {
147	    return [];
148	  }
149	
150	  const actions: PlayerAction[] = [];
151	
152	  for (const { direction } of MOVE_DIRECTIONS) {
153	    const action = { kind: "move", direction } as const;
154	    pushIfLegal(actions, state, action);
155	  }
156	
157	  for (const entity of sortedEntities(state)) {
158	    if (entity.kind === "enemy") {
159	      pushIfLegal(actions, state, {
160	        kind: "attack",
161	        targetId: entity.id,
162	      });
163	    }
164	  }
165	
166	  for (const item of carriedItems(state.player.inventory)) {
167	    pushIfLegal(actions, state, {
168	      kind: "use_item",
169	      itemId: item.itemInstanceId,
170	    });
171	  }
172	
173	  pushIfLegal(actions, state, { kind: "pickup" });
174	
175	  for (const entity of sortedEntities(state)) {
176	    if (entity.kind === "npc") {
177	      pushIfLegal(actions, state, {
178	        kind: "talk",
179	        npcId: entity.id,
180	      });
181	    }
182	  }
183	
184	  pushIfLegal(actions, state, { kind: "wait" });
185	  pushIfLegal(actions, state, { kind: "descend" });
186	  actions.push(...availableInspectActions(state));
187	  pushIfLegal(actions, state, { kind: "abort" });
188	
189	  return actions;
190	};
