 88	function executeDamage(
 89	  state: GameState,
 90	  effect: Effect,
 91	  ctx: EffectExecutionContext
 92	): EffectExecutorResult {
 93	  if (effect.damage === null) {
 94	    return missingPayload(state, effect, ctx);
 95	  }
 96	
 97	  const amount = effect.damage.amount;
 98	  const amountBounds = bounds.effectVocabulary.verbs.damage.amount;
 99	  if (!isSafeIntegerInBounds(amount, amountBounds)) {
100	    return rejectEffect(
101	      state,
102	      effect,
103	      "bounds",
104	      `damage.amount must be ${amountBounds.min}-${amountBounds.max}`,
105	      ctx
106	    );
107	  }
108	
109	  const target = resolveHpTarget(state, ctx);
110	  if (target === null) {
111	    return invalidTarget(
112	      state,
113	      effect,
114	      ctx,
115	      "damage requires a player or enemy target"
116	    );
117	  }
118	
119	  const hpAfter = Math.max(0, target.hpCurrent - amount);
120	  const damagedState = withActorHp(state, target, hpAfter);
121	  const executed = effectExecutedEvent(
122	    state,
123	    "damage",
124	    withResolvedTarget(ctx, target.id),
125	    {
126	      amount,
127	      hpBefore: target.hpCurrent,
128	      hpAfter
129	    }
130	  );
131	
132	  if (hpAfter > 0) {
133	    return {
134	      state: damagedState,
135	      events: [executed]
136	    };
137	  }
138	
139	  const death = applyDeath(damagedState, target.id, {
140	    attribution: deathAttributionFor(ctx.sourceId)
141	  });
142	
143	  return {
144	    state: death.state,
145	    events: [executed, ...death.events]
146	  };
147	}
