212	export const resolveAttack = (
213	  state: GameState,
214	  attackerId: CombatActorId,
215	  defenderId: CombatActorId,
216	): ActionResolverResult => {
217	  const attacker = combatActor(state, attackerId);
218	
219	  if (attacker === null) {
220	    return {
221	      illegal: true,
222	      reason: `attacker ${attackerId} is not a combat actor`,
223	    };
224	  }
225	
226	  const interceptedDefenderId = applyAttackInterceptors(
227	    state,
228	    attackerId,
229	    defenderId,
230	  );
231	  const defender = combatActor(state, interceptedDefenderId);
232	
233	  if (defender === null) {
234	    return {
235	      illegal: true,
236	      reason: `defender ${interceptedDefenderId} is not a combat actor`,
237	    };
238	  }
239	
240	  if (!isAdjacent(attacker.position, defender.position)) {
241	    return {
242	      illegal: true,
243	      reason: `defender ${interceptedDefenderId} is not adjacent to attacker ${attackerId}`,
244	    };
245	  }
246	
247	  return resolveAttackRoll(state, attacker, defender);
248	};
