1471	function retreatStep(
1472	  player: GridPosition,
1473	  cells: readonly GridCell[],
1474	  blockedCells: ReadonlySet<string> = new Set()
1475	): string | null {
1476	  const enemies = visibleEnemyPositions(cells);
1477	  if (enemies.length === 0) {
1478	    return null;
1479	  }
1480	
1481	  const cellMap = cellsByKey(cells);
1482	  const enemyAdjacent = enemyAdjacentKeys(cells);
1483	  const currentDistance = nearestEnemyDistance(player, enemies);
1484	  const candidates = DIRECTIONS.flatMap((direction) => {
1485	    const delta = DIRECTION_DELTAS[direction];
1486	    const destination = {
1487	      x: player.x + delta.x,
1488	      y: player.y + delta.y
1489	    };
1490	    const key = posKey(destination.x, destination.y);
1491	    const cell = cellMap.get(key);
1492	    if (
1493	      cell === undefined ||
1494	      !isWalkable(cell, { blockedCells }) ||
1495	      blockedCells.has(key)
1496	    ) {
1497	      return [];
1498	    }
1499	
1500	    const distance = nearestEnemyDistance(destination, enemies);
1501	    return [
1502	      {
1503	        key: DIRECTION_KEYS[direction],
1504	        destination,
1505	        distance,
1506	        enemyAdjacent: enemyAdjacent.has(key)
1507	      }
1508	    ];
1509	  });
1510	
1511	  const safer = candidates
1512	    .filter((candidate) => candidate.distance > currentDistance)
1513	    .sort(compareRetreatCandidates);
1514	  if (safer.length > 0) {
1515	    return safer[0]!.key;
1516	  }
1517	
1518	  const notAdjacent = candidates
1519	    .filter((candidate) => !candidate.enemyAdjacent)
1520	    .sort(compareRetreatCandidates);
1521	  if (notAdjacent.length > 0) {
1522	    return notAdjacent[0]!.key;
1523	  }
1524	
1525	  const fallback = [...candidates].sort(compareRetreatCandidates);
1526	  return fallback[0]?.key ?? null;
1527	}
