1613	function bfsRouteToPredicate(
1614	  start: GridPosition,
1615	  walkable: ReadonlySet<string>,
1616	  target: (position: GridPosition) => boolean
1617	): GridPosition[] | null {
1618	  if (target(start)) {
1619	    return [start];
1620	  }
1621	
1622	  const queue: GridPosition[][] = [[start]];
1623	  const seen = new Set([posKey(start.x, start.y)]);
1624	
1625	  while (queue.length > 0) {
1626	    const route = queue.shift();
1627	    if (route === undefined) {
1628	      break;
1629	    }
1630	
1631	    const current = route[route.length - 1];
1632	    if (current === undefined) {
1633	      continue;
1634	    }
1635	
1636	    for (const neighbor of neighbors(current)) {
1637	      const key = posKey(neighbor.x, neighbor.y);
1638	      if (seen.has(key) || !walkable.has(key)) {
1639	        continue;
1640	      }
1641	
1642	      const nextRoute = [...route, neighbor];
1643	      if (target(neighbor)) {
1644	        return nextRoute;
1645	      }
1646	
1647	      seen.add(key);
1648	      queue.push(nextRoute);
1649	    }
1650	  }
1651	
1652	  return null;
1653	}
