+      return [];
+    }
+
+    const distance = nearestEnemyDistance(destination, enemies);
+    return [
+      {
+        key: DIRECTION_KEYS[direction],
+        destination,
+        distance,
+        enemyAdjacent: enemyAdjacent.has(key)
